// MutationPredicates returns the list of predicates for update/delete mutations.
func (m *TweetMutation) MutationPredicates() []predicate.Tweet { return m.predicates }

// AddPredicate adds a predicate to the mutation (used by entql filters).
func (m *TweetMutation) AddPredicate(pred func(s *sql.Selector)) {
	m.predicates = append(m.predicates, pred)
}
